  1→import { useCallback, useEffect, useState, useRef } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { TOOLS } from '@/editor/tools';
  6→import { detectRooms } from '@/geometry/roomDetection';
  7→import { createRoom } from '@/domain/models';
  8→import { isTypingTarget } from '@/utils/keyboard';
  9→import styles from './Toolbar.module.css';
 10→
 11→function UndoIcon() {
 12→  return (
 13→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 14→      <path
 15→        d="M6 4 2.5 7.5 6 11"
 16→        fill="none"
 17→        stroke="currentColor"
 18→        strokeWidth="1.5"
 19→        strokeLinecap="round"
 20→        strokeLinejoin="round"
 21→      />
 22→      <path
 23→        d="M3 7.5h5.5A4.5 4.5 0 0 1 13 12"
 24→        fill="none"
 25→        stroke="currentColor"
 26→        strokeWidth="1.5"
 27→        strokeLinecap="round"
 28→        strokeLinejoin="round"
 29→      />
 30→    </svg>
 31→  );
 32→}
 33→
 34→function RedoIcon() {
 35→  return (
 36→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 37→      <path
 38→        d="m10 4 3.5 3.5L10 11"
 39→        fill="none"
 40→        stroke="currentColor"
 41→        strokeWidth="1.5"
 42→        strokeLinecap="round"
 43→        strokeLinejoin="round"
 44→      />
 45→      <path
 46→        d="M13 7.5H7.5A4.5 4.5 0 0 0 3 12"
 47→        fill="none"
