 57→function SidebarIcon() {
 58→  return (
 59→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 60→      <rect x="2" y="3" width="12" height="10" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.3" />
 61→      <path d="M6 3v10" fill="none" stroke="currentColor" strokeWidth="1.3" />
