 64→}
 65→
 66→function PropertiesIcon() {
 67→  return (
 68→    <svg viewBox="0 0 16 16" aria-hidden="true" className={styles.icon}>
 69→      <rect x="2" y="3" width="12" height="10" rx="1.5" fill="none" stroke="currentColor" strokeWidth="1.3" />
 70→      <path d="M10 3v10" fill="none" stroke="currentColor" strokeWidth="1.3" />
 71→    </svg>
