  1→import { lazy, Suspense, useState, useEffect, useCallback, useMemo, useRef } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider, useEditor } from './EditorProvider';
  4→import { ClipboardProvider } from './ClipboardProvider';
  5→import SvgCanvas from '@/renderers/SvgCanvas';
  6→import SheetCanvas from '@/renderers/SheetCanvas';
  7→import Toolbar from '@/ui/Toolbar';
  8→import Sidebar from '@/ui/Sidebar';
  9→import PropertiesPanel from '@/ui/PropertiesPanel';
 10→import Modal from '@/ui/Modal';
 11→import { createProject } from '@/domain/models';
 12→import { getDefaultActiveFloorId, getOrderedFloors } from '@/domain/floorModels';
 13→import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
 14→import {
 15→  exportProjectFile,
 16→  importProjectFile,
 17→  isFilePickerAbortError,
 18→  openProjectFile,
 19→} from '@/persistence/fileTransfer';
 20→import { useAutosave } from '@/persistence/useAutosave';
 21→import { isTypingTarget } from '@/utils/keyboard';
 22→import styles from './App.module.css';
 23→
 24→const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));
 25→
 26→function EditorShell({
 27→  project,
 28→  handleNew,
 29→  handleSave,
 30→  handleLoadClick,
 31→  isSidebarCollapsed,
 32→  isPropertiesCollapsed,
 33→  onToggleSidebar,
 34→  onToggleProperties,
 35→}) {
 36→  const {
 37→    workspaceMode,
 38→    activeSheetId,
 39→    activeFloorId,
 40→    dispatch: editorDispatch,
 41→  } = useEditor();
 42→
 43→  useEffect(() => {
 44→    const sheets = project.sheets || [];
 45→    if (!sheets.length) {
 46→      if (activeSheetId !== null) {
 47→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
 48→      }
 49→      if (workspaceMode === 'sheet') {
 50→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 51→      }
 52→      return;
 53→    }
 54→
 55→    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
 56→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
 57→    }
 58→  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);
 59→
 60→  return (
 61→    <div
 62→      className={styles.layout}
 63→      style={{
 64→        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 65→        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 66→      }}
 67→    >
 68→      <div className={styles.toolbar}>
 69→        <Toolbar
 70→          onNew={handleNew}
 71→          onSave={handleSave}
 72→          onLoad={handleLoadClick}
 73→          isSidebarCollapsed={isSidebarCollapsed}
 74→          isPropertiesCollapsed={isPropertiesCollapsed}
 75→          onToggleSidebar={onToggleSidebar}
 76→          onToggleProperties={onToggleProperties}
 77→        />
 78→      </div>
 79→      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : ''}`}>
 80→        <Sidebar />
 81→      </div>
 82→      <div className={styles.canvas}>
 83→        {workspaceMode === 'sheet' ? (
 84→          <SheetCanvas />
 85→        ) : (
 86→          <div className={styles.modelWorkspace}>
 87→            <div className={styles.primaryCanvas}>
 88→              <SvgCanvas />
 89→            </div>
 90→            <div className={styles.preview}>
 91→              <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
 92→                <ThreePreviewPanel
 93→                  project={project}
 94→                  activeFloorId={activeFloorId}
 95→                />
 96→              </Suspense>
 97→            </div>
 98→          </div>
 99→        )}
100→      </div>
101→      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : ''}`}>
102→        <PropertiesPanel />
103→      </div>
104→    </div>
105→  );
106→}
